INSERT OR IGNORE INTO innovation_theory (id, name_ja, name_en, definition, impact_summary, subfield, category, school_of_thought, era_start, schumpeter_layer, innovation_type, cognitive_mechanism, key_researchers, key_works, keywords_ja, keywords_en) VALUES
('inno_pol_301','国家イノベーション能力指数の構築研究','National Innovation Capacity Index Construction Research','特許・R&D・教育・制度・クラスター環境の複合指標で国家のイノベーション能力を計測する指数を開発した研究群。Porter-Sternの国家イノベーション能力フレームワークとGIIの比較方法論的検討が含まれる。','国家競争力政策のベンチマーク設計と科学技術計画の目標設定に実証的根拠を提供した。','measurement_policy_governance','D_directionality','イノベーション能力計測','2001','macro','policy','national_innovation_capacity','["Porter, M.E.", "Stern, S.", "Furman, J.L."]','["Porter & Stern (2002) National innovative capacity", "Furman et al. (2002) Determinants NIC"]','国家イノベーション能力,複合指標,GII,競争力ベンチマーク','national innovative capacity,composite index,GII,competitiveness benchmark'),
('inno_pol_302','循環経済政策の評価研究','Circular Economy Policy Evaluation Research','EU循環経済行動計画・日本循環型社会形成推進基本法・中国資源節約・環境保護法等の循環経済政策の設計・実施・成果を評価した研究群。EPR（拡大生産者責任）・エコデザイン規制・廃棄物ヒエラルキーの政策効果計測が含まれる。','循環型産業政策と廃棄物管理法制の改革に実証的根拠を提供した。','measurement_policy_governance','D_directionality','循環経済政策研究','2015','macro','policy','circular_economy_policy','["Kirchherr, J.", "Reike, D.", "Hekkert, M."]','["Kirchherr et al. (2017) CE definitions review", "EU Commission (2020) CE action plan"]','循環経済政策,EPR,エコデザイン,廃棄物ヒエラルキー','circular economy policy,EPR,ecodesign,waste hierarchy'),
('inno_pol_303','研究大学の経済インパクト計測','Economic Impact Measurement of Research Universities','大学の研究・教育・スピンオフが地域・国家経済に与える直接・間接インパクトを計測した研究群。産業連関分析・CGE・ヘドニック価格法が用いられ、MIT・Stanford・東大等の事例研究が蓄積されている。','大学への公的投資の費用対効果評価と地域産業政策との連携設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','大学経済インパクト研究','2005','macro','policy','university_economic_impact','["Goldstein, H.A.", "Peer, V.", "Kenney, M."]','["Goldstein et al. (1995) University and community economic development", "Kenney (2000) Understanding Silicon Valley"]','研究大学インパクト,スピンオフ,産業連関,地域経済効果','research university impact,spinoff,input-output analysis,regional economic effect'),
('inno_pol_304','ブロックチェーンガバナンス政策研究','Blockchain Governance Policy Research','パブリック・プライベート・コンソーシアムブロックチェーンのガバナンス構造、DeFi規制、DAO（分散型自律組織）の法的地位を分析した研究群。スマートコントラクトの法的効力・AML規制・脱中央集権と規制可能性の緊張関係が主要テーマとなっている。','ブロックチェーン技術の法制化政策とDeFi規制フレームワーク設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','ブロックチェーンガバナンス研究','2018','macro','policy','blockchain_governance','["Hacker, P.", "Lianos, I.", "Dimitropoulos, G."]','["Hacker et al. (2019) Regulating blockchain", "Lianos et al. (2019) Blockchain DLT regulation"]','ブロックチェーンガバナンス,DeFi規制,DAO,スマートコントラクト','blockchain governance,DeFi regulation,DAO,smart contract'),
('inno_pol_305','科学・技術・イノベーション政策のナラティブ分析','Narrative Analysis of STI Policy','科学技術政策における「ナラティブ」（イノベーション神話・スタートアップ国家の言説・技術的解決主義）の形成と政策選択への影響を批判的に分析した研究群。政策フレーミング・言説分析・政策アイデアの普及メカニズムが主要手法となっている。','STI政策のコミュニケーション設計と政策ナラティブの批判的見直しに実証的根拠を提供した。','measurement_policy_governance','D_directionality','STI政策言説研究','2012','macro','policy','sti_policy_narrative','["Flanagan, K.", "Uyarra, E.", "Arrieta-Paredes, M.P."]','["Flanagan & Uyarra (2016) Reframing regional innovation", "Jasanoff (2015) Dreamscapes of modernity"]','STI政策ナラティブ,言説分析,フレーミング,技術的解決主義','STI policy narrative,discourse analysis,framing,techno-solutionism'),
('inno_pol_306','宇宙経済計測と政策含意','Space Economy Measurement and Policy Implications','商業宇宙産業の経済規模・成長率・雇用・技術スピルオーバー・投資誘発効果を計測した研究群。衛星産業・打ち上げサービス・下流アプリケーション・宇宙観光のセクター別計測方法論が開発されている。','宇宙産業振興政策と宇宙予算配分の費用対効果評価に実証的根拠を提供した。','measurement_policy_governance','D_directionality','宇宙経済計測研究','2017','macro','policy','space_economy_measurement','["Bryce, S.", "OECD", "Space Foundation"]','["OECD (2019) Space Economy at a glance", "Space Foundation (2023) Space Report"]','宇宙経済,商業宇宙,衛星産業,宇宙スピルオーバー','space economy,commercial space,satellite industry,space spillover'),
('inno_pol_307','産学連携成果の長期追跡研究','Long-term Tracking Research of University-Industry Collaboration Outcomes','共同研究・受託研究・インターンシップ・TLOライセンスの産学連携成果を5〜20年追跡した研究群。知識移転の「長い尾」・スピンオフ企業の生存率・共同研究参加学生のキャリアトラジェクトリが主要テーマとなっている。','大学の社会的使命実現と産学連携プログラムの継続的改善に実証的根拠を提供した。','measurement_policy_governance','D_directionality','産学連携長期効果研究','2007','macro','policy','tti_long_term','["Perkmann, M.", "Tartari, V.", "McKelvey, M."]','["Perkmann et al. (2013) Academic engagement activities", "McKelvey & Zaring (2021) Sci-tech entrepreneurship"]','産学連携長期効果,知識移転の長い尾,スピンオフ生存率,ライセンス追跡','university-industry long-term,knowledge transfer long tail,spinoff survival,license tracking'),
('inno_pol_308','イノベーション政策と地域格差：収束・発散論','Innovation Policy and Regional Inequality: Convergence-Divergence Theory','STI政策が地域間経済格差を縮小（収束）させるのか拡大（発散）させるのかを実証分析した研究群。EU構造基金のコホーション効果、スーパースター都市論（tech cluster winner-takes-all）、地方創生政策の効果が主要テーマとなっている。','地域科学技術政策の格差是正設計と地方創生イノベーション戦略に実証的根拠を提供した。','measurement_policy_governance','D_directionality','地域格差・イノベーション政策研究','2010','macro','policy','regional_inequality_innovation','["Moretti, E.", "Rodríguez-Pose, A.", "McCann, P."]','["Moretti (2012) New Geography of Jobs", "Rodríguez-Pose (2018) Revenge of the places that don''t matter"]','地域格差,スーパースター都市,地方創生,EU構造基金','regional inequality,superstar cities,local revitalization,EU structural funds'),
('inno_pol_309','社会的企業家精神と制度変化','Social Entrepreneurship and Institutional Change','社会的企業家が制度的空白・制度的硬直・制度的論理の衝突を利用してイノベーションを推進するメカニズムを分析した研究群。制度的企業家・組織フィールド変革・コンプレックス・アダプティブシステム理論が統合されている。','社会的企業支援政策と制度的エコシステム設計に理論的根拠を提供した。','measurement_policy_governance','D_directionality','社会的企業家精神研究','2007','macro','policy','social_entrepreneurship_institution','["Mair, J.", "Marti, I.", "Battilana, J."]','["Mair & Marti (2006) Social entrepreneurship research", "Battilana & Lee (2014) Advancing research hybrid organizations"]','社会的企業家精神,制度変化,制度的企業家,ハイブリッド組織','social entrepreneurship,institutional change,institutional entrepreneur,hybrid organization'),
('inno_pol_310','新興国のイノベーション政策：後発国モデル','Innovation Policy in Emerging Economies: Late-Mover Model','ブラジル・インド・中国・韓国・台湾等の後発国がキャッチアップ・フォーハウンド・リープフロッグング・フロンティア押し広げの各段階で採用すべきイノベーション政策の違いを分析した研究群。','途上国のイノベーション戦略設計と先進国との連携・競合関係の管理に実証的根拠を提供した。','measurement_policy_governance','D_directionality','新興国イノベーション政策研究','2008','macro','policy','late_mover_innovation','["Lee, K.", "Malerba, F.", "Kim, L."]','["Lee (2013) Schumpeterian Analysis of Economic Catch-up", "Kim (1997) Imitation to Innovation"]','後発国モデル,キャッチアップ,リープフロッギング,フロンティア','late-mover model,catch-up,leapfrogging,frontier'),
('inno_pol_311','研究開発費の国際比較統計（GERD・BERD）','International Comparative Statistics of R&D Expenditure: GERD and BERD','GERDおよびBERDデータの国際比較可能性・測定誤差・GDP比目標（2%・3%ルール）の政策的含意を分析した研究群。R&D統計の品質向上とフラスカティマニュアル改訂の歴史も含まれる。','STI政策の数量的目標設定と国際ベンチマーキングに実証的根拠を提供した。','measurement_policy_governance','D_directionality','R&D統計・計測研究','2000','macro','policy','gerd_berd_statistics','["OECD", "UNESCO", "Godin, B."]','["OECD (2015) Frascati Manual", "Godin (2005) Measurement and statistics science"]','GERD,BERD,R&D統計,GDP比目標','GERD,BERD,R&D statistics,GDP ratio target'),
('inno_pol_312','イノベーション政策のポートフォリオアプローチ','Portfolio Approach to Innovation Policy','単一政策手段ではなく、補助金・税制・規制・調達・標準化を組み合わせた「政策ポートフォリオ」として設計するアプローチを分析した研究群。政策手段間の相補性・代替性・バンドリング効果が主要テーマとなっている。','STI政策の統合設計と省庁横断協働の理論的枠組みとして採用されている。','measurement_policy_governance','D_directionality','政策ポートフォリオ設計研究','2013','macro','policy','policy_portfolio','["Flanagan, K.", "Uyarra, E.", "Laranja, M."]','["Flanagan et al. (2011) Reconceptualising the policy mix", "Laranja et al. (2008) Policies for science, technology and innovation"]','政策ポートフォリオ,政策ミックス,補完性,STI政策設計','policy portfolio,policy mix,complementarity,STI policy design'),
('inno_pol_313','データ主導型政策評価の方法論発展','Methodological Development of Data-Driven Policy Evaluation','行政ビッグデータ・リンク統計・センサスレコードを活用したSTI政策評価の方法論的発展を論じた研究群。マイクロデータのリンケージ・プライバシー保護のための差分プライバシー適用・自動化評価パイプラインが主要テーマとなっている。','政策評価の自動化・精緻化とエビデンスに基づく政策立案（EBPM）の実装に貢献した。','measurement_policy_governance','D_directionality','データ主導政策評価研究','2015','macro','policy','data_driven_policy_eval','["Lane, J.", "Weinberg, B.", "Jarmin, R."]','["Lane (2010) Let us use administrative data", "Jarmin et al. (2014) Linking administrative data"]','データ主導政策評価,行政データ,リンク統計,EBPM','data-driven policy evaluation,administrative data,linked statistics,EBPM'),
('inno_pol_314','国際共同研究の計量書誌学的分析','Bibliometric Analysis of International Research Collaboration','共著ネットワーク・共同特許・共同研究プロジェクトの国際分布と変化を書誌計量的に分析した研究群。研究協力の「グローバル化」・地政学的分断の影響・サイエンス外交との接続が主要テーマとなっている。','国際科学技術協力政策の設計と研究者流動性政策の根拠提供に貢献した。','measurement_policy_governance','D_directionality','国際研究協力計量研究','2010','macro','policy','international_collab_bibliometrics','["Leydesdorff, L.", "Wagner, C.S.", "Noyons, E."]','["Wagner & Leydesdorff (2005) Network structure global science", "Noyons et al. (1999) Bibliometric mapping"]','国際共著ネットワーク,書誌計量,研究協力地政学,サイエンス外交','international co-authorship network,bibliometrics,research collaboration geopolitics,science diplomacy'),
('inno_pol_315','包括的富の指標とイノベーション政策','Inclusive Wealth Indicators and Innovation Policy','GDP を超えた包括的富（人的資本・自然資本・生産資本・社会資本）の計測フレームをSTI政策評価に応用した研究群。UNEP包括的富レポート・Dasguptaレビュー・国連システム・オブ・環境経済勘定（SEEA）との接続が議論されている。','「フェアな」イノベーション政策評価基準の構築と持続可能な発展指標設計に貢献した。','measurement_policy_governance','D_directionality','包括的富・政策評価研究','2012','macro','policy','inclusive_wealth_sti','["Dasgupta, P.", "Arrow, K.J.", "UNEP"]','["UNEP (2012) Inclusive Wealth Report", "Dasgupta (2021) Economics of biodiversity"]','包括的富,自然資本,GDP代替指標,SEEA','inclusive wealth,natural capital,GDP alternative indicators,SEEA'),
('inno_pol_316','技術的失業のエビデンスと政策対応','Evidence on Technological Unemployment and Policy Responses','AI・ロボット化による雇用喪失の実証エビデンス（Acemoglu・Frey等）と政策対応（転業支援・職業訓練・就労奨励税制・UBI実験）を統合的に分析した研究群。','未来の仕事政策と技術転換期の社会安全網設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','技術的失業政策研究','2013','macro','policy','tech_unemployment_evidence','["Frey, C.B.", "Osborne, M.A.", "Acemoglu, D."]','["Frey & Osborne (2013) Future of employment", "Acemoglu & Restrepo (2020) Robots and jobs"]','技術的失業,AI雇用政策,転業支援,UBI実験','technological unemployment,AI employment policy,job transition support,UBI experiment'),
('inno_pol_317','ソーシャルイノベーションの計測と政策','Social Innovation Measurement and Policy','社会的イノベーションの定義・分類・成果計測の多様なアプローチを比較分析した研究群。SROI・社会的インパクト債券・SIE（社会的影響力の測定）・新社会的勘定の方法論的発展が含まれる。','社会的イノベーション政策の費用対効果評価と公共調達での社会価値統合に実証的根拠を提供した。','measurement_policy_governance','D_directionality','ソーシャルイノベーション計測研究','2011','macro','policy','social_innovation_measurement','["Mulgan, G.", "Westley, F.", "Murray, R."]','["Mulgan (2006) Social Innovation", "Murray et al. (2010) Open book of social innovation"]','ソーシャルイノベーション計測,SROI,社会的インパクト,SIB','social innovation measurement,SROI,social impact,SIB'),
('inno_pol_318','ディープテック政策研究','Deep Tech Policy Research','量子・AI・バイオ・核融合・新素材等ディープテックへの政府投資・VC政策・研究機関連携・人材確保の政策設計を分析した研究群。「死の谷」の深化・長期投資家の不在・軍民両用技術のガバナンスが主要テーマとなっている。','ディープテック産業育成政策と次世代研究開発投資戦略に実証的根拠を提供した。','measurement_policy_governance','D_directionality','ディープテック政策研究','2018','macro','policy','deep_tech_policy','["Magnusson, T.", "Berggren, C.", "Zedtwitz, M."]','["Magnusson & Berggren (2018) Entering an era of ferment", "Hello Tomorrow (2019) Deep Tech Report"]','ディープテック,死の谷,長期投資,軍民両用','deep tech,valley of death,long-term investment,dual-use'),
('inno_pol_319','環境規制の競争力効果：Porter仮説の実証研究','Empirical Research on Porter Hypothesis: Competitiveness Effect of Environmental Regulation','厳格な環境規制が長期的にイノベーションを促し競争力を高めるというPorter仮説を多様なデータで検証した研究群。弱いポーター仮説（イノベーション促進）と強いポーター仮説（生産性向上）の識別が主要課題となっている。','環境政策と産業競争力政策の統合設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','Porter仮説実証研究','2003','macro','policy','porter_hypothesis_empirical','["Ambec, S.", "Cohen, M.A.", "Elgie, S."]','["Ambec et al. (2013) Porter hypothesis review", "Lanoie et al. (2011) Porter hypothesis revisited"]','Porter仮説,環境規制競争力,グリーンイノベーション,実証研究','Porter hypothesis,environmental regulation competitiveness,green innovation,empirical'),
('inno_pol_320','技術予測・技術ロードマップ方法論研究','Technology Forecasting and Technology Roadmap Methodology Research','技術Sカーブ・専門家調査・テキストマイニング・機械学習を組み合わせた技術予測の方法論を開発した研究群。技術ロードマップの産業横断標準化・政府主導ロードマップの有効性評価が含まれる。','産業R&D戦略と政府の科学技術基本計画策定に実証的根拠を提供した。','measurement_policy_governance','D_directionality','技術予測方法論研究','2004','macro','policy','tech_roadmap_methodology','["Phaal, R.", "Farrukh, C.J.P.", "Probert, D.R."]','["Phaal et al. (2004) Technology roadmapping", "Kerr & Phaal (2020) Technology roadmapping review"]','技術ロードマップ,技術予測,Sカーブ,R&D戦略','technology roadmap,technology forecasting,S-curve,R&D strategy'),
('inno_pol_321','健康経済とイノベーション投資収益','Health Economics and Innovation Investment Returns','新薬・医療機器・デジタルヘルスへのR&D投資収益率（ROI）・QALYあたりコスト・GDP・労働生産性への経済的波及効果を計測した研究群。医療イノベーションの社会的価値計測の方法論的議論も含まれる。','医療R&D投資政策と医療費適正化・イノベーション促進の均衡設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','医療イノベーション経済研究','2006','macro','policy','health_innovation_roi','["Murphy, K.M.", "Topel, R.H.", "Lakdawalla, D.N."]','["Murphy & Topel (2006) Value of health and longevity", "Lakdawalla et al. (2018) Measuring value innovation"]','医療ROI,QALYコスト,医療イノベーション経済,社会的価値','medical ROI,QALY cost,health innovation economics,social value'),
('inno_pol_322','農業イノベーション政策の国際比較研究','International Comparative Research on Agricultural Innovation Policy','農業R&D補助・普及サービス・種子規制・農業保険・スマート農業政策の国際比較を分析した研究群。CGIAR国際農業研究グループの投資効果・国際技術移転・農業イノベーションシステム評価が含まれる。','食料安全保障政策と農業生産性向上のための研究開発投資設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','農業イノベーション政策研究','2005','macro','policy','agricultural_innovation_policy','["Pardey, P.G.", "Alston, J.M.", "Walker, T.S."]','["Pardey & Alston (2010) Agricultural R&D policy", "Walker et al. (2008) Unlocking CGIAR impact"]','農業イノベーション政策,CGIAR,農業R&D補助,食料安全保障','agricultural innovation policy,CGIAR,agricultural R&D subsidy,food security'),
('inno_pol_323','デジタルエコノミーの生産性計測問題','Productivity Measurement Problem in the Digital Economy','無料デジタルサービス・プラットフォームエコノミー・ビッグデータのGDP統計での計測困難を論じた研究群。消費者余剰の計測・ヘドニック価格指数・SNA（国民勘定体系）改訂の必要性が主要テーマとなっている。','デジタル経済政策の数量的評価基盤の整備と国民経済計算の近代化に理論的根拠を提供した。','measurement_policy_governance','D_directionality','デジタル経済計測研究','2015','macro','policy','digital_economy_measurement','["Brynjolfsson, E.", "Syverson, C.", "Coyle, D."]','["Brynjolfsson et al. (2019) GDP-B welfare", "Coyle (2014) GDP: A Brief but Affectionate History"]','デジタル経済計測,GDP計測問題,消費者余剰,ヘドニック価格','digital economy measurement,GDP measurement problem,consumer surplus,hedonic price'),
('inno_pol_324','グローバル知識経済における研究者移動政策','Researcher Mobility Policy in the Global Knowledge Economy','研究者の国際移動（Brain Drain・Brain Gain・Brain Circulation）がイノベーション生産性・国際研究協力・ホスト/出身国の科学能力に与える影響と政策対応を分析した研究群。','国際研究者流動化政策と研究者キャリア支援制度設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','研究者流動性政策研究','2004','macro','policy','researcher_mobility_policy','["Saxenian, A.", "Beine, M.", "Docquier, F."]','["Saxenian (2006) New Argonauts", "Beine et al. (2008) Brain drain and human capital"]','研究者流動性,Brain Drain,Brain Circulation,国際研究協力','researcher mobility,brain drain,brain circulation,international research collaboration'),
('inno_pol_325','宇宙政策と民間宇宙産業振興','Space Policy and Commercial Space Industry Promotion','NASAの商業乗員・貨物輸送プログラム・JAXA革新的衛星技術・ESAの商業宇宙支援策を比較分析した研究群。公共調達によるイノベーション誘発・固定価格契約と費用精算型契約の比較・NASA→SpaceX知識移転が主要テーマとなっている。','商業宇宙産業振興政策と宇宙公共調達の設計改善に実証的根拠を提供した。','measurement_policy_governance','D_directionality','宇宙産業振興政策研究','2010','macro','policy','commercial_space_policy','["Launius, R.D.", "McCurdy, H.E.", "Paikowsky, D."]','["Launius & McCurdy (2008) Robots in Space", "Paikowsky (2017) US commercial space policy"]','商業宇宙政策,NASA商業プログラム,SpaceX,公共調達イノベーション','commercial space policy,NASA commercial programs,SpaceX,public procurement innovation'),
('inno_pol_326','オープンサイエンス政策の国際比較','International Comparison of Open Science Policy','EU Open Science Policy・NIH Data Sharing Policy・日本オープンサイエンス推進計画等を比較分析した研究群。研究データ共有・論文OA義務化・オープンソフトウェア・オープン教育の政策効果とインセンティブ設計が主要テーマとなっている。','学術出版制度改革と研究資金配分のオープンサイエンス要件設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','オープンサイエンス政策研究','2015','macro','policy','open_science_policy','["Tennant, J.P.", "Crane, H.", "Crick, T."]','["Tennant et al. (2016) Open access citation advantage", "European Commission (2016) Open science policy platform"]','オープンサイエンス政策,OA義務化,データ共有,オープン研究','open science policy,OA mandate,data sharing,open research'),
('inno_pol_327','イノベーション政策の不確実性下での設計','Innovation Policy Design under Uncertainty','ナイトの不確実性・深い不確実性（深い不確実性）の下でのSTI政策設計を分析した研究群。適応的政策管理・頑健な意思決定・シナリオベース政策が主要アプローチとして提案されている。','気候・AI・バイオ等の不確実領域における政策立案の理論的根拠を提供した。','measurement_policy_governance','D_directionality','不確実性下政策設計研究','2010','macro','policy','uncertainty_policy_design','["Walker, W.E.", "Marchau, V.A.W.J.", "Kwakkel, J.H."]','["Walker et al. (2013) Uncertainty in policy analysis", "Marchau et al. (2019) Decision Making under Deep Uncertainty"]','政策不確実性,深い不確実性,適応的政策管理,頑健な意思決定','policy uncertainty,deep uncertainty,adaptive policy management,robust decision-making'),
('inno_pol_328','国際特許制度の改革研究（PCT・EPC）','International Patent System Reform Research: PCT and EPC','PCT（国際特許条約）・EPO（欧州特許庁）・WIPO等の国際特許制度の審査品質・費用・アクセス格差・発展途上国への含意を分析した研究群。特許の国際調和化と各国特許制度の多様性保持の緊張関係が主要テーマとなっている。','国際知的財産政策の設計と発展途上国の特許制度活用に実証的根拠を提供した。','measurement_policy_governance','D_directionality','国際特許制度研究','2005','macro','policy','international_patent_reform','["Dutfield, G.", "Sell, S.K.", "Drahos, P."]','["Dutfield (2003) Intellectual Property and the Life Science Industries", "Drahos (2010) Global Governance IP"]','国際特許制度,PCT,EPO,発展途上国特許','international patent system,PCT,EPO,developing country patent'),
('inno_pol_329','技術官僚制とSTI政策立案能力','Technocracy and STI Policy-Making Capacity','科学技術省庁・国家科学技術委員会・大統領府科学顧問等の技術官僚組織の設計・能力・政策決定への影響を比較分析した研究群。専門知識と民主的正当性の緊張関係・省庁縦割り克服・異分野連携が主要テーマとなっている。','科学技術行政改革と省庁横断STI政策調整機能の強化に実証的根拠を提供した。','measurement_policy_governance','D_directionality','STI行政能力研究','2008','macro','policy','technocracy_sti','["Boekholt, P.", "Arnold, E.", "Braun, D."]','["Boekholt et al. (2010) Lessons from STI governance", "Arnold et al. (2010) STI policy governance"]','技術官僚制,STI政策能力,省庁横断,科学顧問','technocracy,STI policy capacity,cross-ministry,science advisory'),
('inno_pol_330','エコシステムマッピングツールの政策活用','Policy Use of Ecosystem Mapping Tools','スタートアップエコシステム・クラスター・産業ネットワークのマッピングツール（Startup Genome・Dealroom・EY Navigator）の政策立案・産業振興への活用方法を分析した研究群。データ品質・指標選定・ベンチマーク比較の方法論的問題が議論されている。','地域産業政策の診断ツール設計とエコシステム介入の根拠提供に実証的根拠を提供した。','measurement_policy_governance','D_directionality','エコシステムマッピング政策研究','2015','meso','policy','ecosystem_mapping_policy','["Isenberg, D.J.", "Stam, E.", "Spigel, B."]','["Stam (2015) Entrepreneurial ecosystems and regional policy", "Spigel (2017) Relational organization entrepreneurial ecosystems"]','エコシステムマッピング,スタートアップ診断,Startup Genome,地域産業政策','ecosystem mapping,startup diagnostics,Startup Genome,regional industrial policy'),
('inno_pol_331','核不拡散体制とデュアルユース核技術政策','Non-Proliferation Regime and Dual-Use Nuclear Technology Policy','NPT・IAEA保障措置・原子力サプライヤーグループ（NSG）等の核不拡散体制が民間核技術・核燃料サイクル・SMR普及に与える影響を分析した研究群。核セキュリティとエネルギー政策の接点での政策設計が主要テーマとなっている。','核エネルギー政策の国際ガバナンスと民間核産業振興の均衡設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','核技術・不拡散政策研究','2005','macro','policy','nuclear_nonproliferation_policy','["Hecht, G.", "Hymans, J.E.C.", "Fuhrmann, M."]','["Hecht (2012) Being Nuclear", "Hymans (2006) Psychology nuclear proliferation"]','核不拡散,NPT,IAEA,SMR政策','nuclear nonproliferation,NPT,IAEA,SMR policy'),
('inno_pol_332','科学技術政策の歴史的分析','Historical Analysis of Science Technology Policy','バネバー・ブッシュ報告・ソビエト科学政策・日本の科学技術基本計画・EU研究枠組みの歴史的展開を分析した研究群。科学政策の「リニアモデル」批判とポスト線形モデルへの移行が主要テーマとなっている。','現在のSTI政策パラダイムの歴史的文脈理解と政策学習への活用に貢献した。','measurement_policy_governance','D_directionality','STI政策史研究','2002','macro','policy','sti_policy_history','["Godin, B.", "Edgerton, D.", "Krige, J."]','["Godin (2006) Knowledge-based economy", "Krige (2006) American Hegemony Cold War science"]','科学技術政策史,リニアモデル批判,バネバーブッシュ,EU研究枠組み','STI policy history,linear model critique,Vannevar Bush,EU research framework'),
('inno_pol_333','プラットフォーム経済の課税と規制統合研究','Integrated Research on Platform Economy Taxation and Regulation','デジタルプラットフォームに対する税制・競争法・消費者保護法・労働法の統合的規制アプローチを分析した研究群。欧州デジタル市場法（DMA）・米国プラットフォーム法案・日本特定デジタルプラットフォーム透明化法の比較が含まれる。','プラットフォーム規制の包括的設計と競争・税・労働政策の整合性確保に実証的根拠を提供した。','measurement_policy_governance','D_directionality','プラットフォーム統合規制研究','2020','macro','policy','platform_integrated_regulation','["Crémer, J.", "Marsden, P.", "Cobbe, J."]','["EU Commission (2020) DMA proposal", "Crémer et al. (2019) Policy challenges digital platforms"]','プラットフォーム統合規制,DMA,競争法,デジタル課税','platform integrated regulation,DMA,competition law,digital taxation'),
('inno_pol_334','バイオエコノミー政策研究','Bioeconomy Policy Research','農業・食品・化学・医薬・エネルギー分野でのバイオ資源利用による「バイオエコノミー」の政策設計（EU Bioeconomy Strategy・米国Bioeconomy Blueprint・日本バイオ戦略）を比較分析した研究群。','持続可能な産業転換政策と生物資源の経済的活用に実証的根拠を提供した。','measurement_policy_governance','D_directionality','バイオエコノミー政策研究','2012','macro','policy','bioeconomy_policy','["McCormick, K.", "Kautto, N.", "Urmetzer, S."]','["McCormick & Kautto (2013) Bioeconomy", "EU Commission (2018) EU Bioeconomy Strategy update"]','バイオエコノミー政策,EU Bioeconomy Strategy,日本バイオ戦略,生物資源','bioeconomy policy,EU Bioeconomy Strategy,Japan bio strategy,bioresources'),
('inno_pol_335','科学技術政策のパラドックス：支援と規制の矛盾','Paradoxes of STI Policy: Contradictions between Support and Regulation','同一政府が一方でR&Dを補助しながら他方で競争法・安全規制・知財法で技術普及を制限するという「政策の矛盾」を体系的に分析した研究群。規制の一貫性・政策シナジー・政策キャンセルメカニズムが主要テーマとなっている。','STI政策の統合設計と省庁横断ガバナンス改革に理論的根拠を提供した。','measurement_policy_governance','D_directionality','STI政策パラドックス研究','2014','macro','policy','sti_policy_paradox','["Edler, J.", "Blind, K.", "Frietsch, R."]','["Edler & Blind (2019) Innovation policy paradox", "Frietsch et al. (2010) Policy mix"]','政策の矛盾,STIパラドックス,規制一貫性,政策キャンセル','policy contradiction,STI paradox,regulatory consistency,policy cancellation'),
('inno_pol_336','イノベーション政策の学習と適応：政策実験','Learning and Adaptation in Innovation Policy: Policy Experiments','小規模パイロット→評価→スケールアップという政策実験サイクルを通じた学習型政策の設計・実施を分析した研究群。エビデンスに基づく政策拡張・失敗からの学習・ポリシーラボの機能が主要テーマとなっている。','政府のイノベーション政策サイクルの近代化と適応型政策設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','政策実験・学習研究','2016','macro','policy','policy_experiment_learning','["Breckon, J.", "Hopkins, A.", "Rickey, B."]','["Breckon (2015) Using Research Evidence in Policy", "NESTA (2018) Experimental approaches government"]','政策実験,政策学習,ポリシーラボ,スケールアップ','policy experiment,policy learning,policy lab,scale-up'),
('inno_pol_337','ガバメントテックとデジタル政府変革','GovTech and Digital Government Transformation','行政手続きのデジタル化・データ分析活用型行政・AIによる政策立案支援など「ガバメントテック」の発展と課題を分析した研究群。レガシーシステム・調達改革・デジタル能力・市民との信頼が主要テーマとなっている。','行政DX政策と政府のサービスデザイン能力向上に実証的根拠を提供した。','measurement_policy_governance','D_directionality','ガバメントテック政策研究','2016','macro','policy','govtech_policy','["Mergel, I.", "Edelmann, N.", "Haug, N."]','["Mergel et al. (2019) Digital transformation government", "OECD (2020) Digital government index"]','ガバメントテック,行政DX,デジタル政府,調達改革','GovTech,government DX,digital government,procurement reform'),
('inno_pol_338','イノベーション政策のグローバルガバナンス（WTO・WIPO・UN）','Global Governance of Innovation Policy: WTO, WIPO, and UN','WTO TRIPSs協定・WIPO開発アジェンダ・UNESCO科学勧告・G20イノベーション作業部会等の国際機関がイノベーション政策の国際ルール形成に与える影響を分析した研究群。','イノベーション政策の国際協調設計と多国間ガバナンス体制の強化に実証的根拠を提供した。','measurement_policy_governance','D_directionality','イノベーション国際ガバナンス研究','2008','macro','policy','global_innovation_governance','["Drahos, P.", "Sell, S.K.", "Wade, R.H."]','["Sell (2003) Private power, public law TRIPS", "Wade (2003) Governing the market"]','国際イノベーションガバナンス,TRIPS,WIPO開発アジェンダ,G20','global innovation governance,TRIPS,WIPO development agenda,G20'),
('inno_pol_339','技術的加速度の計測研究（ムーア則・ライトの法則）','Measurement of Technological Acceleration: Moore''s Law and Wright''s Law','ムーアの法則（半導体集積度）・ライトの法則（学習曲線・経験曲線）・Swansonの法則（太陽光コスト）など技術コスト低下・性能向上の指数的進歩を計測する方法論を開発した研究群。技術予測への応用と法則適用限界の分析も含まれる。','技術ロードマップ策定と産業転換期の政策タイミング設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','技術加速度計測研究','2010','macro','product','technological_acceleration','["Nagy, B.", "Farmer, J.D.", "Bui, Q.M."]','["Nagy et al. (2013) Statistical basis for predicting technological progress", "Farmer & Lafond (2016) How predictable is technological progress"]','ムーア則,ライト則,技術コスト低下,技術加速度計測','Moore''s law,Wright''s law,technology cost decline,technological acceleration measurement'),
('inno_pol_340','ネットゼロ移行のイノベーション計測','Innovation Measurement for Net-Zero Transition','ネットゼロ達成に必要なクリーンテクノロジーの技術成熟度・投資ギャップ・特許動向・市場準備性を計測する方法論を開発した研究群。IEAのエネルギー技術展望・BloombergNEF・Mission Innovation等の統計フレームが比較されている。','ネットゼロ政策の進捗評価と技術投資優先度設定に実証的根拠を提供した。','measurement_policy_governance','D_directionality','ネットゼロイノベーション計測研究','2020','macro','policy','net_zero_innovation_measurement','["IEA", "BloombergNEF", "Grubb, M."]','["IEA (2021) Net Zero by 2050", "BloombergNEF (2023) New Energy Outlook"]','ネットゼロ計測,クリーンテクノロジー,技術成熟度,投資ギャップ','net-zero measurement,clean technology,technology readiness,investment gap'),
('inno_pol_341','国家AI戦略の比較評価研究','Comparative Evaluation Research of National AI Strategies','米国AIイニシアティブ・EU AI戦略・中国新世代AI発展計画・日本AI戦略等の国家AI戦略を比較評価した研究群。投資規模・研究重点・産業応用・倫理・安全要件の国際差異と戦略的含意が分析されている。','AI政策の国際競争環境の把握と国家AI戦略の設計改善に実証的根拠を提供した。','measurement_policy_governance','D_directionality','国家AI戦略研究','2019','macro','policy','national_ai_strategy','["Canziani, O.", "Floridi, L.", "Dutton, T."]','["Dutton (2018) AI Strategy national comparison", "OECD (2022) AI Policy Observatory"]','国家AI戦略,AI政策比較,中国AI計画,EU AI戦略','national AI strategy,AI policy comparison,China AI plan,EU AI strategy'),
('inno_pol_342','エネルギー安全保障とイノベーション政策の統合','Integration of Energy Security and Innovation Policy','エネルギー安全保障（多様化・強靭性・自給率）とイノベーション促進政策の整合的設計を分析した研究群。ロシア-ウクライナ戦争後のエネルギー安全保障危機がクリーンエネルギーイノベーション加速に与えた影響の実証研究も含まれる。','エネルギー政策・安全保障政策・イノベーション政策の統合設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','エネルギー安全保障政策研究','2022','macro','policy','energy_security_innovation','["Yergin, D.", "Overland, I.", "Scholten, D."]','["Yergin (2011) The Quest", "Overland (2019) Geopolitics of renewable energy"]','エネルギー安全保障,再エネ加速,地政学,エネルギーイノベーション','energy security,renewable acceleration,geopolitics,energy innovation'),
('inno_pol_343','科学技術指標の非西洋文脈への適用研究','Application of STI Indicators to Non-Western Contexts','OECD・GIIを始めとするイノベーション指標が西洋中心のイノベーション概念に依拠しており、アフリカ・東南アジア・中東のイノベーション実態を計測するのに限界があることを分析した研究群。代替指標の開発と計測の文脈依存性が主要テーマとなっている。','途上国のイノベーション政策評価基盤の構築と指標の文化的包摂性向上に貢献した。','measurement_policy_governance','D_directionality','非西洋STI指標研究','2015','macro','policy','non_western_sti_indicators','["Kaplinsky, R.", "Morris, M.", "Archibugi, D."]','["Kaplinsky & Morris (2015) Tectonic shifts global innovation", "Archibugi et al. (2009) The global dimension innovation"]','非西洋STI指標,アフリカイノベーション,代替計測,文脈依存','non-western STI indicators,African innovation,alternative measurement,context-dependence'),
('inno_pol_344','デジタル公共財政策研究','Digital Public Goods Policy Research','Wikipedia・OpenStreetMap・Linux・DHIS2等デジタル公共財への公的投資・ガバナンス・持続可能性を分析した研究群。DPGA（デジタル公共財アライアンス）の設計と途上国デジタル主権との接続が主要テーマとなっている。','デジタル公共財への国際的投資枠組みと途上国デジタル自立支援に実証的根拠を提供した。','measurement_policy_governance','D_directionality','デジタル公共財政策研究','2020','macro','policy','digital_public_goods_policy','["DPGA", "Gurstein, M.", "Kaye, D."]','["DPGA (2020) Digital Public Goods Standard", "Gurstein (2011) Open data civic enablement"]','デジタル公共財,DPGA,デジタル主権,途上国デジタル','digital public goods,DPGA,digital sovereignty,developing country digital'),
('inno_pol_345','バイオプロスペクティングと遺伝資源アクセス政策','Bioprospecting and Genetic Resource Access Policy','名古屋議定書のABS（アクセスと利益配分）ルール・生物多様性条約・植物遺伝資源条約等が生物資源を活用したイノベーション（医薬品・農業・化粧品）に与える影響を分析した研究群。','生物多様性保全政策とバイオ産業イノベーションの公平な利益配分設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','遺伝資源政策研究','2010','macro','policy','bioprospecting_policy','["Parry, B.", "Dutfield, G.", "Kamau, E.C."]','["Parry (2004) Trading the genome", "Dutfield (2004) Intellectual property, biogenetic resources"]','ABS,名古屋議定書,生物多様性条約,遺伝資源','ABS,Nagoya Protocol,Convention on Biological Diversity,genetic resources'),
('inno_pol_346','宇宙資源利用の法制度研究','Legal Framework Research on Space Resource Utilization','米国宇宙法（SPACE Act）・ルクセンブルク宇宙法・UAE宇宙資源法等の宇宙資源採掘に関する国内法制と宇宙条約（OST）整合性を分析した研究群。月・小惑星の採掘権・汚染防止義務・非専有原則の解釈論争が主要テーマとなっている。','宇宙資源経済の法的基盤整備と国際宇宙法改革交渉に実証的根拠を提供した。','measurement_policy_governance','D_directionality','宇宙資源法政策研究','2015','macro','policy','space_resources_law','["Pop, V.", "Jakhu, R.S.", "Tronchetti, F."]','["Pop (2000) Who owns the moon", "Jakhu et al. (2017) Space mining legal"]','宇宙資源採掘,SPACE Act,宇宙条約,月採掘権','space resource mining,SPACE Act,Outer Space Treaty,lunar mining rights'),
('inno_pol_347','イノベーション政策の経路依存性研究','Path Dependency Research in Innovation Policy','過去の政策・制度・技術選択が現在の政策オプション集合を制約する「経路依存性」のSTI政策への影響を分析した研究群。原子力ロックイン・自動車産業保護・農業補助金の経路依存解除の政策設計が主要テーマとなっている。','産業転換・技術転換期の政策設計とレジーム変革政策の理論的根拠を提供した。','measurement_policy_governance','D_directionality','政策経路依存研究','2006','macro','policy','policy_path_dependency','["Pierson, P.", "Arthur, W.B.", "David, P.A."]','["Pierson (2000) Increasing returns path dependence", "David (1985) QWERTY"]','経路依存性,ロックイン,レジーム変革,政策転換','path dependency,lock-in,regime change,policy transition'),
('inno_pol_348','医療テクノロジー政策のHTA国際ネットワーク','HTA International Networks in Healthcare Technology Policy','EUNetHTA・INAHTA・HTAi等のHTA国際ネットワークが医療技術の国際的評価協調・二重評価削減・小国の評価能力向上に与える影響を分析した研究群。EU HTA規制（Regulation EU 2021/2282）の施行評価が含まれる。','医療技術評価の国際整合と医薬品アクセス政策の公平性向上に実証的根拠を提供した。','measurement_policy_governance','D_directionality','HTA国際協調研究','2014','macro','policy','hta_international_network','["Kleijnen, S.", "Toumi, M.", "Drummond, M.F."]','["Kleijnen et al. (2012) EUnetHTA effectiveness", "EU Regulation 2021/2282 HTA"]','HTA国際ネットワーク,EUNetHTA,EU HTA規制,医療技術評価協調','HTA international network,EUNetHTA,EU HTA regulation,healthcare technology assessment collaboration'),
('inno_pol_349','STI政策のジェンダー主流化研究','Gender Mainstreaming in STI Policy Research','EU Horizon Europe ジェンダー平等計画義務・NIH性別を考慮した研究政策・NSERC自然科学工学評議会のDEI要件等のSTI政策へのジェンダー主流化の成果を評価した研究群。研究設計・採用・資金配分の性差分析が含まれる。','科学技術政策のジェンダー包摂性向上と研究の質向上に実証的根拠を提供した。','measurement_policy_governance','D_directionality','ジェンダー主流化政策研究','2013','macro','policy','gender_mainstreaming_sti','["Schiebinger, L.", "Klinge, I.", "Riegraf, B."]','["Schiebinger (2010) Gender innovation", "Klinge (2008) Establishing gendered innovations"]','ジェンダー主流化,Horizon Europe,性差分析,DEI研究','gender mainstreaming,Horizon Europe,sex-gender analysis,DEI research'),
('inno_pol_350','グリーン水素政策の国際比較研究','International Comparative Research on Green Hydrogen Policy','EU水素戦略・米国水素ロードマップ・日本水素社会実現ロードマップ・韓国水素経済路線図を比較分析した研究群。製造コスト低下軌跡・輸送インフラ・グリーン認証標準・国際水素貿易の政策設計が主要テーマとなっている。','水素エネルギー産業政策と脱炭素移行の技術選択設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','グリーン水素政策研究','2020','macro','policy','green_hydrogen_policy','["IRENA", "IEA", "Hydrogen Council"]','["IRENA (2022) Global hydrogen trade", "IEA (2021) Net Zero Hydrogen"]','グリーン水素政策,水素戦略,水素ロードマップ,水素貿易','green hydrogen policy,hydrogen strategy,hydrogen roadmap,hydrogen trade');
